KQL:
// Objective: Tracks interactive user sign-in success and failure events in Entra ID,
// with conditional access evaluation, device trust, and geo-location context.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
// Leave arrays empty to return all results. Add specific values to scope.
//
let TargetUsers = dynamic([]);       // e.g., ["alice@contoso.com"]
let TargetApps = dynamic([]);        // e.g., ["Microsoft Teams"]
//
// ----- Part 1: Filter for Interactive Sign-Ins -----
//
SigninLogs
| where TimeGenerated > ago(30d)
//
// ----- Part 2: Parse Device and Location Context -----
//
| extend
    DeviceOS = tostring(parse_json(DeviceDetail).operatingSystem),
    DeviceTrust = tostring(parse_json(DeviceDetail).trustType),
    DeviceBrowser = tostring(parse_json(DeviceDetail).browser),
    LocationCity = tostring(LocationDetails.city),
    LocationCountry = tostring(LocationDetails.countryOrRegion),
    CAStatus = tostring(ConditionalAccessStatus)
//
// ----- Part 3: Enrich with Human-Readable Result -----
//
| extend ResultDescription = case(
    ResultType == 0, "Success",
    ResultType == 50074, "Strong Auth Required",
    ResultType == 50076, "MFA Required - User did not pass",
    ResultType == 53003, "Blocked by Conditional Access",
    ResultType == 50126, "Invalid username or password",
    ResultType == 50140, "Keep me signed in interrupt",
    strcat("Error-", tostring(ResultType))
)
//
// ----- Part 4: Apply Dynamic Filters -----
//
| where (array_length(TargetUsers) == 0 or UserPrincipalName in (TargetUsers))
| where (array_length(TargetApps) == 0 or AppDisplayName in (TargetApps))
//
// ----- Part 5: Final Output -----
//
| distinct TimeGenerated, UserPrincipalName, AppDisplayName, ResultType, ResultDescription,
           CAStatus, IPAddress, LocationCity, LocationCountry, DeviceOS, DeviceTrust,
           AuthenticationRequirement, UserType
| sort by TimeGenerated desc
| take 50

// Objective: Tracks non-interactive (token refresh, SSO, OBO) sign-in activity in Entra ID
// to detect credential replay, stale sessions, or unauthorized token usage.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetUsers = dynamic([]);        // e.g., ["user1@contoso.com"]
let TargetApps = dynamic([]);         // e.g., ["Microsoft Graph"]
//
// ----- Part 1: Filter for Non-Interactive Sign-Ins -----
//
AADNonInteractiveUserSignInLogs
| where TimeGenerated > ago(30d)
//
// ----- Part 2: Parse Status Details -----
//
| extend
    StatusCode = tostring(parse_json(Status).errorCode),
    FailureReason = tostring(parse_json(Status).failureReason)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetUsers) == 0 or UserPrincipalName in (TargetUsers))
| where (array_length(TargetApps) == 0 or AppDisplayName in (TargetApps))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, UserPrincipalName, AppDisplayName, ResourceDisplayName,
           ResultType, StatusCode, FailureReason, IPAddress, UserAgent
| sort by TimeGenerated desc
| take 50

// Objective: Tracks which authentication methods were used for interactive Entra ID
// sign-ins (MFA, FIDO2, passwordless, etc.) to validate credential policy compliance.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetUsers = dynamic([]);            // e.g., ["alice@contoso.com"]
let TargetAuthMethods = dynamic([]);      // e.g., ["Password", "FIDO2"]
//
// ----- Part 1: Filter and Parse Authentication Details -----
//
SigninLogs
| where TimeGenerated > ago(30d)
| mv-expand AuthenticationDetail = todynamic(AuthenticationDetails)
| extend
    AuthMethod = tostring(AuthenticationDetail.authenticationMethod),
    AuthStepRequirement = tostring(AuthenticationDetail.authenticationStepRequirement),
    AuthResult = tostring(AuthenticationDetail.succeeded)
| where AuthMethod != "Previously satisfied"
| where isnotempty(AuthMethod)
//
// ----- Part 2: Apply Dynamic Filters -----
//
| where (array_length(TargetUsers) == 0 or UserPrincipalName in (TargetUsers))
| where (array_length(TargetAuthMethods) == 0 or AuthMethod in (TargetAuthMethods))
//
// ----- Part 3: Final Output -----
//
| summarize SigninCount = count()
    by TimeGenerated, UserPrincipalName, AppDisplayName, AuthMethod, AuthStepRequirement, AuthResult
| sort by TimeGenerated desc
| take 50

// Objective: Detects user lifecycle events (creation, deletion, role/group changes, guest invites)
// in Entra ID to track who granted or revoked system access and when.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetOperations = dynamic([]);    // e.g., ["Add user", "Delete user", "Add member to role", "Remove member from role", "Add member to group", "Remove member from group", "Invite external user"]
let TargetInitiators = dynamic([]);    // e.g., ["admin@contoso.com"]
//
// ----- Part 1: Filter for User Lifecycle Operations -----
//
AuditLogs
| where TimeGenerated > ago(30d)
| where (array_length(TargetOperations) == 0 or OperationName has_any (TargetOperations))
//
// ----- Part 2: Extract Initiator and Target Details -----
//
| extend InitiatorInfo = todynamic(InitiatedBy)
| extend TargetInfo = todynamic(TargetResources)[0]
| extend
    InitiatorType = case(
        isnotempty(tostring(InitiatorInfo.user.userPrincipalName)), "User",
        isnotempty(tostring(InitiatorInfo.app.displayName)), "Application",
        "Other"),
    Initiator = coalesce(
        tostring(InitiatorInfo.user.userPrincipalName),
        tostring(InitiatorInfo.app.displayName)),
    InitiatorIP = tostring(InitiatorInfo.user.ipAddress),
    TargetUPN = tostring(TargetInfo.userPrincipalName),
    TargetDisplayName = tostring(TargetInfo.displayName)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetInitiators) == 0 or Initiator in (TargetInitiators))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, OperationName, InitiatorType, Initiator, InitiatorIP,
           TargetUPN, TargetDisplayName, Result, Category
| sort by TimeGenerated desc
| take 50

// Objective: Evaluates Conditional Access policy enforcement per sign-in event
// to verify that access decisions (grant, block, MFA) are applied correctly.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetUsers = dynamic([]);       // e.g., ["alice@contoso.com"]
let TargetPolicies = dynamic([]);    // e.g., ["Require MFA - All Users"]
//
// ----- Part 1: Filter for Sign-Ins with CA Evaluation -----
//
SigninLogs
| where TimeGenerated > ago(30d)
| where ConditionalAccessPolicies != "[]"
//
// ----- Part 2: Expand CA Policy Array -----
//
| mv-expand CAPolicy = todynamic(ConditionalAccessPolicies)
| extend
    PolicyName = tostring(CAPolicy.displayName),
    PolicyResult = tostring(CAPolicy.result),
    GrantControls = tostring(CAPolicy.enforcedGrantControls),
    SessionControls = tostring(CAPolicy.enforcedSessionControls)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetUsers) == 0 or UserPrincipalName in (TargetUsers))
| where (array_length(TargetPolicies) == 0 or PolicyName in (TargetPolicies))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, UserPrincipalName, AppDisplayName, PolicyName, PolicyResult,
           GrantControls, SessionControls, ResultType, IPAddress, ConditionalAccessStatus
| sort by TimeGenerated desc
| take 50

// Objective: Tracks all successful (4624) and failed (4625) user logon activity in Windows
// SecurityEvent logs with logon type classification and authentication protocol enrichment.
//
// GPO Path: Computer Configuration > Policies > Windows Settings > Security Settings >
// Advanced Audit Policy Configuration > Logon/Logoff > Audit Logon (Success, Failure)
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetComputers = dynamic([]);     // e.g., ["DC01.contoso.com"]
let TargetAccountSIDs = dynamic([]);   // e.g., ["S-1-5-21-..."]
//
// ----- Part 1: Filter for 4624/4625 Events -----
//
SecurityEvent
| where TimeGenerated > ago(14d)
| where EventID in (4624, 4625)
| where AccountType == "User"
| where not(TargetUserName has_any ("$", "SYSTEM", "LOCAL SERVICE", "NETWORK SERVICE"))
//
// ----- Part 2: Classify Logon Type and Auth Protocol -----
//
| extend
    LogonTypeName = case(
        LogonType == 2, "Interactive (Console)",
        LogonType == 3, "Network",
        LogonType == 4, "Batch",
        LogonType == 5, "Service",
        LogonType == 7, "Unlock",
        LogonType == 8, "NetworkCleartext",
        LogonType == 9, "NewCredentials",
        LogonType == 10, "RemoteInteractive (RDP)",
        LogonType == 11, "CachedInteractive",
        "Other"),
    AuthenticationProtocol = case(
        TargetUserName == "ANONYMOUS LOGON", "N/A (Anonymous)",
        AuthenticationPackageName == "NTLM" and LmPackageName == "NTLM V1", "NTLMv1",
        AuthenticationPackageName == "NTLM" and LmPackageName == "NTLM V2", "NTLMv2",
        AuthenticationPackageName == "Kerberos", "Kerberos",
        AuthenticationPackageName),
    IsAnonymous = (TargetUserName == "ANONYMOUS LOGON")
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetComputers) == 0 or Computer in (TargetComputers))
| where (array_length(TargetAccountSIDs) == 0 or TargetUserSid in (TargetAccountSIDs))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, Computer, EventID, Activity, TargetUserName, TargetUserSid,
           LogonTypeName, AuthenticationProtocol, IsAnonymous, IpAddress, WorkstationName
| sort by TimeGenerated desc
| take 50

// Objective: Provides a point-in-time inventory of all identity objects enriched by
// Sentinel UEBA, including department, job title, risk level, and group membership.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetDepartments = dynamic([]);   // e.g., ["Finance", "IT"]
let TargetRiskLevels = dynamic([]);    // e.g., ["high", "medium"]
//
// ----- Part 1: Get Latest Identity Snapshot -----
//
IdentityInfo
| where TimeGenerated > ago(14d)
| summarize arg_max(TimeGenerated, *) by AccountUPN
//
// ----- Part 2: Apply Dynamic Filters -----
//
| where (array_length(TargetDepartments) == 0 or Department in (TargetDepartments))
| where (array_length(TargetRiskLevels) == 0 or RiskLevel in (TargetRiskLevels))
//
// ----- Part 3: Final Output -----
//
| project TimeGenerated, AccountUPN, AccountDisplayName, Department, JobTitle,
         Manager, City, Country, IsAccountEnabled, RiskLevel, RiskState, GroupMembership
| sort by AccountUPN asc
| take 50

// Objective: Surfaces anomalous user behavior flagged by Sentinel UEBA with
// investigation priority scoring, activity insights, and device context.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetUsers = dynamic([]);    // e.g., ["admin@contoso.com"]
let MinPriority = 0;              // Minimum investigation priority score
//
// ----- Part 1: Filter for Anomalous Behavior -----
//
BehaviorAnalytics
| where TimeGenerated > ago(30d)
| where InvestigationPriority > MinPriority
//
// ----- Part 2: Apply Dynamic Filters -----
//
| where (array_length(TargetUsers) == 0 or UserPrincipalName in (TargetUsers))
//
// ----- Part 3: Final Output -----
//
| distinct TimeGenerated, UserPrincipalName, ActionType, SourceDevice, SourceIPAddress,
           InvestigationPriority, ActivityInsights, UsersInsights, DevicesInsights
| sort by InvestigationPriority desc, TimeGenerated desc
| take 50

// Objective: Summarizes on-premises AD logon activity (success/failure) captured by
// Microsoft Defender for Identity sensors, with cloud service and auth protocol context.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetAccounts = dynamic([]);     // e.g., ["svc_account", "admin1"]
//
// ----- Part 1: Filter for Logon Events -----
//
IdentityLogonEvents
| where TimeGenerated > ago(30d)
| where (array_length(TargetAccounts) == 0 or AccountName in~ (TargetAccounts))
//
// ----- Part 2: Parse Additional Fields for Cloud Context -----
//
| extend AF = parse_json(AdditionalFields)
| extend
    CloudService = tostring(AF['TO.CLOUD_SERVICE']),
    PassThroughAuth = tostring(AF['Pass-through authentication'])
//
// ----- Part 3: Summarize Logon Activity -----
//
| summarize
    TotalEvents = count(),
    FailedLogons = countif(ActionType =~ "LogonFailed"),
    SuccessfulLogons = countif(ActionType =~ "LogonSuccess"),
    DistinctCloudServices = make_set(CloudService, 5),
    DistinctIPs = make_set(IPAddress, 5),
    LastLogonTime = arg_max(TimeGenerated, AccountUpn, Application, OSPlatform, Location, ISP)
    by AccountName, AccountDomain
//
// ----- Part 4: Final Output -----
//
| distinct AccountName, AccountDomain, AccountUpn, Application, OSPlatform, Location, ISP,
           TotalEvents, SuccessfulLogons, FailedLogons, tostring(DistinctCloudServices),
           tostring(DistinctIPs), LastLogonTime
| sort by TotalEvents desc
| take 50

// Objective: Tracks on-premises AD directory changes captured by MDI sensors including
// account lifecycle, group membership, and password events.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetAccounts = dynamic([]);     // e.g., ["admin@contoso.com"]
let TargetActions = dynamic([]);    // e.g., ["Group Membership changed", "Account password changed", "Account was disabled", "Account was enabled", "Account was created", "Account was deleted"]
//
// ----- Part 1: Filter for Directory Change Events -----
//
IdentityDirectoryEvents
| where Timestamp > ago(30d)
| where (array_length(TargetActions) == 0 or ActionType has_any (TargetActions))
//
// ----- Part 2: Parse Additional Fields -----
//
| extend AF = parse_json(AdditionalFields)
| extend
    TargetObject = tostring(AF['TO.OBJECT']),
    FromObject = tostring(AF['FROM.OBJECT']),
    TargetAccountUpn = tostring(AF['TARGET_OBJECT.USER'])
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetAccounts) == 0 or AccountUpn in (TargetAccounts))
//
// ----- Part 4: Final Output -----
//
| distinct Timestamp, AccountUpn, AccountDisplayName, ActionType, DeviceName,
           DestinationDeviceName, TargetObject, FromObject
| sort by Timestamp desc
| take 50

// Objective: Tracks automated user provisioning/deprovisioning events across SaaS apps
// integrated with Entra ID provisioning, to verify lifecycle management compliance.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetSystems = dynamic([]);     // e.g., ["ServiceNow", "Salesforce"]
let TargetActions = dynamic([]);     // e.g., ["Create", "Disable"]
//
// ----- Part 1: Filter for Provisioning Events -----
//
AADProvisioningLogs
| where TimeGenerated > ago(30d)
//
// ----- Part 2: Extract Source and Target Identity -----
//
| extend
    SourceIdentityName = tostring(parse_json(SourceIdentity).Name),
    SourceIdentityId = tostring(parse_json(SourceIdentity).Id),
    TargetIdentityName = tostring(parse_json(TargetIdentity).Name),
    TargetIdentityId = tostring(parse_json(TargetIdentity).Id)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetSystems) == 0 or TargetSystem in (TargetSystems))
| where (array_length(TargetActions) == 0 or Action in (TargetActions))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, SourceIdentityName, TargetIdentityName, Action,
           TargetSystem, SourceSystem, ResultType, StatusInfo
| sort by TimeGenerated desc
| take 50

// Objective: Provides a point-in-time inventory of users flagged as risky by
// Entra ID Protection, with risk level, state, and last-updated context.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetUsers = dynamic([]);       // e.g., ["user@contoso.com"]
let TargetRiskLevels = dynamic([]);    // e.g., ["low", "medium", "high"]
//
// ----- Part 1: Filter for Risky Users -----
//
AADRiskyUsers
| where TimeGenerated > ago(30d)
| where (array_length(TargetRiskLevels) == 0 or RiskLevel has_any (TargetRiskLevels))
//
// ----- Part 2: Deduplicate to Latest State -----
//
| summarize arg_max(TimeGenerated, *) by UserPrincipalName
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetUsers) == 0 or UserPrincipalName in (TargetUsers))
//
// ----- Part 4: Final Output -----
//
| project TimeGenerated, UserPrincipalName, UserDisplayName, RiskLevel, RiskState,
         RiskDetail, RiskLastUpdatedDateTime, IsDeleted, IsProcessing
| sort by RiskLevel desc
| take 50

// Objective: Tracks individual risk detection events raised by Entra ID Protection
// (impossible travel, anonymous IP, token anomaly, etc.) with timing and source context.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetUsers = dynamic([]);        // e.g., ["user@contoso.com"]
let TargetRiskTypes = dynamic([]);    // e.g., ["impossibleTravel", "anonymizedIPAddress"]
//
// ----- Part 1: Filter for Risk Events -----
//
AADUserRiskEvents
| where TimeGenerated > ago(30d)
//
// ----- Part 2: Apply Dynamic Filters -----
//
| where (array_length(TargetUsers) == 0 or UserPrincipalName in (TargetUsers))
| where (array_length(TargetRiskTypes) == 0 or RiskEventType in (TargetRiskTypes))
//
// ----- Part 3: Final Output -----
//
| distinct TimeGenerated, UserPrincipalName, UserDisplayName, RiskEventType, RiskLevel,
           RiskState, RiskDetail, IpAddress, Location, DetectionTimingType, Source
| sort by TimeGenerated desc
| take 50

// Objective: Tracks non-human (service principal) sign-in activity to detect
// unauthorized application access to resources or APIs.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetSPs = dynamic([]);          // e.g., ["MyApp-ServicePrincipal"]
let TargetResources = dynamic([]);    // e.g., ["Microsoft Graph", "Key Vault"]
//
// ----- Part 1: Filter for Service Principal Sign-Ins -----
//
AADServicePrincipalSignInLogs
| where TimeGenerated > ago(30d)
//
// ----- Part 2: Parse Status Details -----
//
| extend
    StatusCode = tostring(parse_json(Status).errorCode),
    FailureReason = tostring(parse_json(Status).failureReason)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetSPs) == 0 or ServicePrincipalName in (TargetSPs))
| where (array_length(TargetResources) == 0 or ResourceDisplayName in (TargetResources))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, ServicePrincipalName, ServicePrincipalId, ResourceDisplayName,
           IPAddress, ResultType, StatusCode, FailureReason, AppId
| sort by TimeGenerated desc
| take 50

// Objective: Tracks managed identity sign-in activity to detect unauthorized
// Azure resource-to-resource access via system or user-assigned managed identities.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetMIs = dynamic([]);          // e.g., ["myvm-identity"]
let TargetResources = dynamic([]);    // e.g., ["Key Vault", "Storage"]
//
// ----- Part 1: Filter for Managed Identity Sign-Ins -----
//
AADManagedIdentitySignInLogs
| where TimeGenerated > ago(30d)
//
// ----- Part 2: Apply Dynamic Filters -----
//
| where (array_length(TargetMIs) == 0 or ServicePrincipalName in (TargetMIs))
| where (array_length(TargetResources) == 0 or ResourceDisplayName in (TargetResources))
//
// ----- Part 3: Final Output -----
//
| distinct TimeGenerated, ServicePrincipalName, ResourceDisplayName, IPAddress,
           ResultType, Location, FederatedCredentialId
| sort by TimeGenerated desc
| take 50

// Objective: Detects privilege escalation by tracking app consent, delegated permission grants,
// and app role assignments — highlighting newly delegated permissions to applications.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetSPs = dynamic([]);       // e.g., ["MyAppServicePrincipal"]
let TargetActors = dynamic([]);    // e.g., ["admin@contoso.com"]
//
// ----- Part 1: Filter for Consent and Permission Grant Operations -----
//
AuditLogs
| where TimeGenerated > ago(30d)
| where OperationName in (
    "Consent to application",
    "Add app role assignment grant to user",
    "Add delegated permission grant",
    "Add app role assignment to service principal",
    "Add OAuth2PermissionGrant")
//
// ----- Part 2: Extract Initiator and Target Details -----
//
| extend
    Actor = coalesce(
        tostring(parse_json(tostring(InitiatedBy.user)).userPrincipalName),
        tostring(parse_json(tostring(InitiatedBy.app)).displayName)),
    ActorIPAddress = tostring(parse_json(tostring(InitiatedBy.user)).ipAddress),
    TargetApp = tostring(TargetResources[0].displayName),
    TargetAppId = tostring(TargetResources[0].id),
    AppRoleAdded = tostring(parse_json(tostring(parse_json(tostring(
        TargetResources[0].modifiedProperties))[1].newValue)))
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetSPs) == 0 or TargetApp in (TargetSPs))
| where (array_length(TargetActors) == 0 or Actor in (TargetActors))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, OperationName, Actor, ActorIPAddress, TargetApp,
           TargetAppId, AppRoleAdded, Result
| sort by TimeGenerated desc
| take 50

// Objective: Tracks Entra ID directory role membership changes (Global Admin, Security Admin, etc.)
// to detect unauthorized privilege grants or revocations.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetRoles = dynamic([]);       // e.g., ["Global Administrator", "Security Administrator"]
let TargetActors = dynamic([]);      // e.g., ["admin@contoso.com"]
//
// ----- Part 1: Filter for Role Membership Operations -----
//
AuditLogs
| where TimeGenerated > ago(30d)
| where OperationName in (
    "Add member to role",
    "Add eligible member to role",
    "Add scoped member to role",
    "Remove member from role")
//
// ----- Part 2: Extract Role and Target Details -----
//
| extend
    Actor = coalesce(
        tostring(InitiatedBy.user.userPrincipalName),
        tostring(InitiatedBy.app.displayName)),
    ActorIP = tostring(InitiatedBy.user.ipAddress),
    TargetUser = tostring(TargetResources[0].userPrincipalName),
    TargetDisplayName = tostring(TargetResources[0].displayName),
    RoleName = tostring(parse_json(tostring(
        TargetResources[0].modifiedProperties))[1].displayName)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetActors) == 0 or Actor in (TargetActors))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, OperationName, Actor, ActorIP, TargetUser,
           TargetDisplayName, RoleName, Result
| sort by TimeGenerated desc
| take 50

// Objective: Tracks write/modify operations against Microsoft Graph API to detect
// privilege escalation via role management, policy changes, or app registration modifications.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetMethods = dynamic([]);    // e.g., ["PATCH", "POST", "DELETE", "PUT"]
let TargetPathKeywords = dynamic([]);  // e.g., ["roleManagement", "appRoleAssignments"]
//
// ----- Part 1: Filter for Write Operations -----
//
MicrosoftGraphActivityLogs
| where TimeGenerated > ago(30d)
| where (array_length(TargetMethods) == 0 or RequestMethod in (TargetMethods))
//
// ----- Part 2: Parse URI and Classify Sensitivity -----
//
| extend UriPath = tostring(parse_url(RequestUri).Path)
| extend IsPrivileged = UriPath has_any (
    "roleManagement", "directoryRoles", "appRoleAssignments",
    "oauth2PermissionGrants", "policies", "servicePrincipals",
    "applications", "groups")
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetPathKeywords) == 0 or UriPath has_any (TargetPathKeywords))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, RequestMethod, UriPath, ResponseStatusCode, AppId,
           ServicePrincipalId, UserId, IPAddress, IsPrivileged, UserAgent
| sort by TimeGenerated desc
| take 50

// Objective: Provides a point-in-time inventory of service principals flagged as risky
// by Entra ID Protection to identify compromised or misconfigured applications.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetSPs = dynamic([]);    // e.g., ["MyApp"]
//
// ----- Part 1: Filter and Deduplicate -----
//
AADRiskyServicePrincipals
| where TimeGenerated > ago(30d)
| summarize arg_max(TimeGenerated, *) by ServicePrincipalId
//
// ----- Part 2: Apply Dynamic Filters -----
//
| where (array_length(TargetSPs) == 0 or ServicePrincipalName in (TargetSPs))
//
// ----- Part 3: Final Output -----
//
| project TimeGenerated, ServicePrincipalName, ServicePrincipalId, AppId,
         RiskLevel, RiskState, RiskDetail, RiskLastUpdatedDateTime, IsEnabled, IsProcessing
| sort by RiskLevel desc
| take 50

// Objective: Tracks individual risk detection events raised against service principals
// by Entra ID Protection (anomalous activity, suspicious sign-ins, etc.).
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetSPs = dynamic([]);          // e.g., ["MyApp"]
let TargetRiskTypes = dynamic([]);    // e.g., ["suspiciousSignins"]
//
// ----- Part 1: Filter for SP Risk Events -----
//
AADServicePrincipalRiskEvents
| where TimeGenerated > ago(30d)
//
// ----- Part 2: Apply Dynamic Filters -----
//
| where (array_length(TargetSPs) == 0 or ServicePrincipalName in (TargetSPs))
| where (array_length(TargetRiskTypes) == 0 or RiskEventType in (TargetRiskTypes))
//
// ----- Part 3: Final Output -----
//
| distinct TimeGenerated, ServicePrincipalName, ServicePrincipalId, RiskEventType,
           RiskLevel, RiskState, DetectionTimingType, IpAddress, KeyIds, Source
| sort by TimeGenerated desc
| take 50

// Objective: Detects cloud app consent, OAuth authorization, and app role assignment events
// captured by Microsoft Defender for Cloud Apps to identify unauthorized privilege grants.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetActions = dynamic([]);    // e.g., ["AppConsent", "AddAppRoleAssignment", "DelegatedPermissionGrant", "OAuthAppAuthorization"]
let TargetAccounts = dynamic([]);    // e.g., ["admin@contoso.com"]
//
// ----- Part 1: Filter for Privilege Escalation Events -----
//
CloudAppEvents
| where TimeGenerated > ago(30d)
| where (array_length(TargetActions) == 0 or ActionType has_any (TargetActions))
//
// ----- Part 2: Apply Dynamic Filters -----
//
| where (array_length(TargetAccounts) == 0 or AccountId in (TargetAccounts))
//
// ----- Part 3: Final Output -----
//
| distinct TimeGenerated, ActionType, AccountId, Application, ObjectName,
           ObjectType, IPAddress, CountryCode, City
| sort by TimeGenerated desc
| take 50

// Objective: Monitors execution of command-line interpreters and LOLBins on endpoints
// to detect unauthorized function execution, encoded commands, or living-off-the-land techniques.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetDevices = dynamic([]);    // e.g., ["WORKSTATION01"]
let SuspiciousProcesses = dynamic([]);    // e.g., ["powershell.exe", "cmd.exe", "wscript.exe", "cscript.exe", "mshta.exe", "rundll32.exe", "regsvr32.exe", "certutil.exe"]
//
// ----- Part 1: Filter for Suspicious Process Execution -----
//
DeviceProcessEvents
| where Timestamp > ago(7d)
| where (array_length(SuspiciousProcesses) == 0 or FileName has_any (SuspiciousProcesses))
//
// ----- Part 2: Classify Encoded/Obfuscated Commands -----
//
| extend
    CommandLineLength = strlen(ProcessCommandLine),
    IsEncoded = ProcessCommandLine has_any ("-enc", "-encoded", "FromBase64", "-e "),
    IsDownloader = ProcessCommandLine has_any ("Invoke-WebRequest", "wget",
        "curl", "DownloadString", "DownloadFile", "Start-BitsTransfer")
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetDevices) == 0 or DeviceName in (TargetDevices))
//
// ----- Part 4: Final Output -----
//
| distinct Timestamp, DeviceName, FileName, ProcessCommandLine, AccountName,
           AccountDomain, InitiatingProcessFileName, FolderPath,
           CommandLineLength, IsEncoded, IsDownloader
| sort by Timestamp desc
| take 50

// Objective: Monitors DLL/image loads from non-standard paths (temp, AppData, Downloads)
// to detect sideloading, unsigned library injection, or unauthorized code execution.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetDevices = dynamic([]);    // e.g., ["SERVER01"]
let SuspiciousPaths = dynamic([]);    // e.g., ["\\temp\\", "\\appdata\\", "\\downloads\\", "\\public\\"]
//
// ----- Part 1: Filter for Loads from Suspicious Paths -----
//
DeviceImageLoadEvents
| where Timestamp > ago(7d)
| where (array_length(SuspiciousPaths) == 0 or FolderPath has_any (SuspiciousPaths))
//
// ----- Part 2: Check Signer Information -----
//
| extend
    IsSigned = isnotempty(Signer),
    IsMicrosoftSigned = Signer has "Microsoft"
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetDevices) == 0 or DeviceName in (TargetDevices))
//
// ----- Part 4: Final Output -----
//
| distinct Timestamp, DeviceName, FileName, FolderPath, SHA256, Signer,
           IsSigned, IsMicrosoftSigned, InitiatingProcessFileName,
           InitiatingProcessFolderPath
| sort by Timestamp desc
| take 50

// Objective: Tracks Azure RBAC role assignment changes at the subscription or resource level
// to detect unauthorized privilege grants or lateral movement via Owner/Contributor roles.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetCallers = dynamic([]);    // e.g., ["admin@contoso.com"]
let TargetScopes = dynamic([]);     // e.g., ["/subscriptions/..."]
//
// ----- Part 1: Filter for Role Assignment Write/Delete -----
//
AzureActivity
| where TimeGenerated > ago(30d)
| where OperationNameValue in (
    "MICROSOFT.AUTHORIZATION/ROLEASSIGNMENTS/WRITE",
    "MICROSOFT.AUTHORIZATION/ROLEASSIGNMENTS/DELETE")
| where ActivityStatusValue == "Success"
//
// ----- Part 2: Parse Caller and Scope -----
//
| extend
    RequestBody = parse_json(tostring(parse_json(Properties).requestbody)),
    Scope = tostring(parse_json(Properties).scope)
| extend
    RoleDefinitionId = tostring(RequestBody.properties.roleDefinitionId),
    PrincipalId = tostring(RequestBody.properties.principalId)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetCallers) == 0 or Caller in (TargetCallers))
| where (array_length(TargetScopes) == 0 or Scope has_any (TargetScopes))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, OperationNameValue, Caller, CallerIpAddress, Scope,
           RoleDefinitionId, PrincipalId, ActivityStatusValue, SubscriptionId
| sort by TimeGenerated desc
| take 50

// Objective: Detects cross-tenant and external (B2B guest) sign-in activity to verify
// that inbound and outbound identity federation is authorized and controlled.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetUsers = dynamic([]);          // e.g., ["guest@partner.com"]
let HomeTenantFilter = dynamic([]);     // Your tenant ID to detect outbound
//
// ----- Part 1: Filter for Cross-Tenant Sign-Ins -----
//
SigninLogs
| where TimeGenerated > ago(30d)
| where HomeTenantId != ResourceTenantId or UserType == "Guest"
//
// ----- Part 2: Classify Cross-Tenant Direction -----
//
| extend CrossTenantType = case(
    UserType == "Guest", "Inbound Guest",
    HomeTenantId != ResourceTenantId, "Outbound to External Resource",
    "Other")
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetUsers) == 0 or UserPrincipalName in (TargetUsers))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, UserPrincipalName, AppDisplayName, CrossTenantType,
           HomeTenantId, ResourceTenantId, IPAddress, ResultType,
           ConditionalAccessStatus, UserType
| sort by TimeGenerated desc
| take 50

// Objective: Tracks B2B guest invitations, invite redemptions, and cross-tenant access
// settings changes to detect unauthorized external identity federation.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetOperations = dynamic([]);    // e.g., ["Invite external user", "Redeem external user invite", "Add partner to cross-tenant access setting", "Update cross-tenant access setting"]
let TargetInitiators = dynamic([]);    // e.g., ["admin@contoso.com"]
//
// ----- Part 1: Filter for External Identity Operations -----
//
AuditLogs
| where TimeGenerated > ago(30d)
| where (array_length(TargetOperations) == 0 or OperationName has_any (TargetOperations))
//
// ----- Part 2: Extract Initiator and Target -----
//
| extend
    Initiator = coalesce(
        tostring(InitiatedBy.user.userPrincipalName),
        tostring(InitiatedBy.app.displayName)),
    InitiatorIP = tostring(InitiatedBy.user.ipAddress),
    TargetUser = tostring(TargetResources[0].userPrincipalName),
    TargetDisplayName = tostring(TargetResources[0].displayName)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetInitiators) == 0 or Initiator in (TargetInitiators))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, OperationName, Initiator, InitiatorIP, TargetUser,
           TargetDisplayName, Result, Category
| sort by TimeGenerated desc
| take 50

// Objective: Tracks user activity within sanctioned and unsanctioned cloud applications
// captured by Defender for Cloud Apps to detect unauthorized external system usage.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetApps = dynamic([]);        // e.g., ["Dropbox", "Box"]
let TargetAccounts = dynamic([]);    // e.g., ["user@contoso.com"]
//
// ----- Part 1: Filter for Cloud App Events -----
//
CloudAppEvents
| where TimeGenerated > ago(30d)
//
// ----- Part 2: Apply Dynamic Filters -----
//
| where (array_length(TargetApps) == 0 or Application in (TargetApps))
| where (array_length(TargetAccounts) == 0 or AccountId in (TargetAccounts))
//
// ----- Part 3: Final Output -----
//
| distinct TimeGenerated, ActionType, AccountId, Application, ObjectName,
           ObjectType, IPAddress, CountryCode, City, UserAgent
| sort by TimeGenerated desc
| take 50

// Objective: Provides a traffic-based inventory of discovered (shadow IT) cloud applications
// with user count, session count, and data volume to identify unsanctioned external systems.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetApps = dynamic([]);    // e.g., ["Dropbox", "WeTransfer"]
//
// ----- Part 1: Aggregate Discovery Data -----
//
McasShadowItReporting
| where TimeGenerated > ago(30d)
//
// ----- Part 2: Summarize by App -----
//
| summarize
    TotalTrafficBytes = sum(UploadedBytes + DownloadedBytes),
    UserCount = dcount(EnrichedUserName),
    SessionCount = count()
    by StreamName, AppName = tostring(AppName)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetApps) == 0 or AppName in (TargetApps))
//
// ----- Part 4: Final Output -----
//
| project AppName, StreamName, TotalTrafficBytes, UserCount, SessionCount
| sort by TotalTrafficBytes desc
| take 50

// Objective: Monitors outbound network connections from endpoints to external IPs
// on sensitive ports to detect unauthorized connections to external information systems.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetDevices = dynamic([]);    // e.g., ["SERVER01"]
let SuspiciousPorts = dynamic([]);    // e.g., [445, 3389, 22, 23, 1433, 3306, 5432]
//
// ----- Part 1: Filter for Successful Outbound Connections -----
//
DeviceNetworkEvents
| where Timestamp > ago(7d)
| where ActionType == "ConnectionSuccess"
| where (array_length(SuspiciousPorts) == 0 or RemotePort in (SuspiciousPorts)) or not(ipv4_is_private(RemoteIP))
//
// ----- Part 2: Classify Public vs Private -----
//
| extend IsPublicDest = not(ipv4_is_private(RemoteIP))
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetDevices) == 0 or DeviceName in (TargetDevices))
//
// ----- Part 4: Final Output -----
//
| distinct Timestamp, DeviceName, InitiatingProcessFileName, RemoteIP, RemotePort,
           RemoteUrl, LocalIP, LocalPort, IsPublicDest, Protocol
| sort by Timestamp desc
| take 50

// Objective: Provides a point-in-time network configuration inventory for managed endpoints
// including IP addresses, adapters, DNS, and tunnel type to verify connection posture.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetDevices = dynamic([]);    // e.g., ["LAPTOP01"]
//
// ----- Part 1: Get Latest Network Config -----
//
DeviceNetworkInfo
| where Timestamp > ago(1d)
//
// ----- Part 2: Expand IP Addresses -----
//
| mv-expand IPInfo = parse_json(IPAddresses)
| extend
    IPAddress = tostring(IPInfo.IPAddress),
    SubnetPrefix = tostring(IPInfo.SubnetPrefix)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetDevices) == 0 or DeviceName in (TargetDevices))
//
// ----- Part 4: Final Output -----
//
| distinct Timestamp, DeviceName, NetworkAdapterName, MacAddress, NetworkAdapterType,
           IPAddress, SubnetPrefix, ConnectedNetworks, DnsAddresses, TunnelType
| sort by DeviceName asc
| take 50

// Objective: Tracks Azure Firewall application and network rule evaluations to verify
// that outbound connections to external systems are authorized and logged.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetSourceIPs = dynamic([]);    // e.g., ["10.0.1.5"]
let TargetActions = dynamic([]);      // e.g., ["Deny"]
//
// ----- Part 1: Filter for Azure Firewall Events -----
//
AzureDiagnostics
| where TimeGenerated > ago(7d)
| where Category has "AzureFirewall"
| where OperationName has_any ("AzureFirewallApplicationRule", "AzureFirewallNetworkRule")
//
// ----- Part 2: Parse Rule Action Details -----
//
| extend ParsedMsg = parse_json(msg_s)
| extend
    SourceIP = tostring(split(tostring(ParsedMsg), " ")[3]),
    DestIP = tostring(split(tostring(ParsedMsg), " ")[5]),
    Action = tostring(split(tostring(ParsedMsg), " ")[0])
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetSourceIPs) == 0 or SourceIP in (TargetSourceIPs))
| where (array_length(TargetActions) == 0 or Action in (TargetActions))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, Resource, OperationName, SourceIP, DestIP, Action, msg_s
| sort by TimeGenerated desc
| take 50

// Objective: Analyzes NSG flow logs for outbound connections to public IP addresses
// to detect unauthorized egress or data exfiltration to external systems.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetNSGs = dynamic([]);    // e.g., ["myVnet-nsg"]
//
// ----- Part 1: Filter for Outbound Flows to Public IPs -----
//
AzureNetworkAnalytics_CL
| where TimeGenerated > ago(7d)
| where SubType_s == "FlowLog"
| where FlowDirection_s == "O"
//
// ----- Part 2: Identify Public Destinations -----
//
| extend IsPublicDest = not(ipv4_is_private(DestIP_s))
| where IsPublicDest == true
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetNSGs) == 0 or NSGName_s in (TargetNSGs))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, NSGName_s, SrcIP_s, DestIP_s, DestPort_d,
           FlowDirection_s, FlowStatus_s, L7Protocol_s,
           AllowedOutFlows_d, DeniedOutFlows_d
| sort by TimeGenerated desc
| take 50

// Objective: Tracks sensitivity label application, changes, and removals on documents
// and emails to verify that public information is properly classified before distribution.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetLabels = dynamic([]);    // e.g., ["Public", "Confidential"]
let TargetUsers = dynamic([]);     // e.g., ["user@contoso.com"]
//
// ----- Part 1: Filter for Label Events -----
//
InformationProtectionEvents_CL
| where TimeGenerated > ago(30d)
//
// ----- Part 2: Apply Dynamic Filters -----
//
| where (array_length(TargetLabels) == 0 or LabelName_s in (TargetLabels))
| where (array_length(TargetUsers) == 0 or UserId_s in (TargetUsers))
//
// ----- Part 3: Final Output -----
//
| distinct TimeGenerated, UserId_s, LabelName_s, Activity_s, ObjectId_s,
           MachineName_s, Application_s, DeviceName_s
| sort by TimeGenerated desc
| take 50

// Objective: Tracks Data Loss Prevention policy matches and enforcement actions
// to verify that sensitive or controlled information is not posted to public systems.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetPolicies = dynamic([]);      // e.g., ["Block CUI External Sharing"]
let TargetSeverities = dynamic([]);    // e.g., ["High", "Medium"]
//
// ----- Part 1: Filter for DLP Actions -----
//
DLPActionEvents
| where TimeGenerated > ago(30d)
//
// ----- Part 2: Parse Sensitive Info Type -----
//
| extend SensitiveInfoType = tostring(SensitiveInfoTypeData)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetPolicies) == 0 or PolicyName in (TargetPolicies))
| where (array_length(TargetSeverities) == 0 or Severity in (TargetSeverities))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, PolicyName, RuleName, ActionType, TargetFilePath,
           SharePointSiteUrl, AccountName, SensitiveInfoType, Severity
| sort by TimeGenerated desc
| take 50

// Objective: Tracks administrative changes to sensitivity label definitions and policies
// to detect unauthorized weakening of classification controls for public information.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetOperations = dynamic([]);    // e.g., ["Set-Label", "New-LabelPolicy", "Set-LabelPolicy", "Remove-Label", "Remove-LabelPolicy"]
let TargetActors = dynamic([]);    // e.g., ["compliance-admin@contoso.com"]
//
// ----- Part 1: Filter for Label Policy Operations -----
//
AuditLogs
| where TimeGenerated > ago(30d)
| where (array_length(TargetOperations) == 0 or OperationName has_any (TargetOperations))
//
// ----- Part 2: Extract Actor and Target -----
//
| extend
    Actor = coalesce(
        tostring(InitiatedBy.user.userPrincipalName),
        tostring(InitiatedBy.app.displayName)),
    ActorIP = tostring(InitiatedBy.user.ipAddress),
    TargetName = tostring(TargetResources[0].displayName)
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetActors) == 0 or Actor in (TargetActors))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, OperationName, Actor, ActorIP, TargetName, Result, Category
| sort by TimeGenerated desc
| take 50

// Objective: Surfaces active security recommendations related to public exposure
// (internet-facing, unrestricted access, public storage) from Microsoft Defender for Cloud.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetKeywords = dynamic([]);    // e.g., ["public", "internet", "exposed", "unrestricted", "anonymous", "open"]
//
// ----- Part 1: Filter for Active Public Exposure Recommendations -----
//
SecurityRecommendation
| where RecommendationState == "Active"
| where (array_length(TargetKeywords) == 0 or Properties has_any (TargetKeywords))
//
// ----- Part 2: Extract Resource and Control Details -----
//
| extend
    ResourceName = tostring(parse_json(Properties).resourceName),
    ControlName = tostring(parse_json(Properties).controlName)
//
// ----- Part 3: Final Output -----
//
| distinct TimeGenerated, RecommendationDisplayName, RecommendationState,
           ResourceName, ControlName, RecommendationSeverity, Description
| sort by RecommendationSeverity desc
| take 50

// Objective: Surfaces security alerts related to publicly exposed resources
// (storage blobs, internet-facing VMs, open databases) from Defender for Cloud.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetSeverities = dynamic([]);    // e.g., ["High", "Medium"]
let ExposureKeywords = dynamic([]);    // e.g., ["public", "exposed", "internet-facing", "storage", "blob", "anonymous access"]
//
// ----- Part 1: Filter for Exposure-Related Alerts -----
//
SecurityAlert
| where TimeGenerated > ago(30d)
| where (array_length(TargetSeverities) == 0 or AlertSeverity has_any (TargetSeverities))
| where (array_length(ExposureKeywords) == 0 or Description has_any (ExposureKeywords))
//
// ----- Part 2: Final Output -----
//
| distinct TimeGenerated, AlertName, AlertSeverity, Description,
           RemediationSteps, ProviderName, ResourceId, Status, Entities
| sort by TimeGenerated desc
| take 50

// Objective: Detects external file sharing events (anonymous links, guest invitations,
// uploads to public sites) in cloud apps monitored by Defender for Cloud Apps.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetActions = dynamic([]);    // e.g., ["SharingSet", "AnonymousLinkCreated", "CompanyLinkCreated", "SharingInvitationCreated", "FileUploaded"]
let TargetAccounts = dynamic([]);    // e.g., ["user@contoso.com"]
//
// ----- Part 1: Filter for Sharing and Upload Events -----
//
CloudAppEvents
| where TimeGenerated > ago(30d)
| where (array_length(TargetActions) == 0 or ActionType has_any (TargetActions))
//
// ----- Part 2: Apply Dynamic Filters -----
//
| where (array_length(TargetAccounts) == 0 or AccountId in (TargetAccounts))
//
// ----- Part 3: Final Output -----
//
| distinct TimeGenerated, ActionType, AccountId, Application, ObjectName,
           ObjectType, IPAddress, CountryCode
| sort by TimeGenerated desc
| take 50

// Objective: Tracks SharePoint and OneDrive external sharing activity including anonymous links,
// guest invitations, and company-wide links to verify public information control.
//
// ----- Part 0: Analyst-Driven Targeting (Optional) -----
//
let TargetOperations = dynamic([]);    // e.g., ["SharingSet", "AnonymousLinkCreated", "SharingInvitationCreated", "CompanyLinkCreated", "AnonymousLinkUsed", "SharingInvitationAccepted"]
let TargetUsers = dynamic([]);    // e.g., ["user@contoso.com"]
//
// ----- Part 1: Filter for SharePoint/OneDrive Sharing Events -----
//
OfficeActivity
| where TimeGenerated > ago(30d)
| where RecordType in (6, 14)
| where (array_length(TargetOperations) == 0 or Operation has_any (TargetOperations))
//
// ----- Part 2: Extract Target User -----
//
| extend TargetUserOrGroup = tostring(TargetUserOrGroupName)
| extend IsExternalShare = TargetUserOrGroup has "#ext#" or TargetUserOrGroup has "urn:spo:guest"
//
// ----- Part 3: Apply Dynamic Filters -----
//
| where (array_length(TargetUsers) == 0 or UserId in (TargetUsers))
//
// ----- Part 4: Final Output -----
//
| distinct TimeGenerated, UserId, Operation, OfficeObjectId, Site_Url,
           TargetUserOrGroup, IsExternalShare, ClientIP, OfficeWorkload
| sort by TimeGenerated desc
| take 50

// NIST 3.10.1 - Sign-Ins from Untrusted/Unknown Locations
// Part 0: Analyst-Driven Targeting
let TargetUsers = dynamic(["*"]);
let TrustedCountries = dynamic([]);    // e.g., ["US", "CA"]
let LookbackDays = 30;
// Part 1: Base Filter
SigninLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where ResultType == "0"
| where (UserPrincipalName has_any (TargetUsers) or TargetUsers has "*")
// Part 2: Enrichment
| extend Country = tostring(LocationDetails.countryOrRegion)
| extend City = tostring(LocationDetails.city)
| where (array_length(TrustedCountries) == 0 or not(Country in (TrustedCountries)))
// Final Output
| project TimeGenerated, UserPrincipalName, AppDisplayName, Country, City, IPAddress, ConditionalAccessStatus, DeviceDetail, AuthenticationRequirement
| sort by TimeGenerated desc
| take 50

// NIST 3.10.1 - CA Policy Location-Based Blocks
// Part 0: Analyst-Driven Targeting
let TargetUsers = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
SigninLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where ConditionalAccessStatus == "failure"
| where (UserPrincipalName has_any (TargetUsers) or TargetUsers has "*")
// Part 2: Enrichment
| mv-expand CAPolicy = parse_json(ConditionalAccessPolicies)
| extend PolicyName = tostring(CAPolicy.displayName)
| extend PolicyResult = tostring(CAPolicy.result)
| where PolicyResult == "failure"
| extend Country = tostring(LocationDetails.countryOrRegion)
// Final Output
| project TimeGenerated, UserPrincipalName, AppDisplayName, PolicyName, PolicyResult, Country, IPAddress, ResultType, ResultDescription
| sort by TimeGenerated desc
| take 50

// NIST 3.10.1 - Device Compliance State for Physical Access Control
// Part 0: Analyst-Driven Targeting
let TargetOS = dynamic(["*"]);
let TargetCompliance = dynamic([]);    // e.g., ["Noncompliant", "InGracePeriod", "Unknown"]
// Part 1: Base Filter
IntuneDevices
| where TimeGenerated > ago(1d)
| where (array_length(TargetCompliance) == 0 or ComplianceState has_any (TargetCompliance))
| where (OS has_any (TargetOS) or TargetOS has "*")
// Part 2: Enrichment
| summarize arg_max(TimeGenerated, *) by DeviceId
| extend DaysSinceContact = datetime_diff('day', now(), LastContact)
// Final Output
| project TimeGenerated, DeviceName, UserName, OS, OSVersion, ComplianceState, OwnerType, LastContact, DaysSinceContact, SerialNumber
| sort by ComplianceState asc
| take 50

// NIST 3.10.3 - Guest (Visitor) Sign-In Activity
// Part 0: Analyst-Driven Targeting
let TargetGuests = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
SigninLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where UserType == "Guest"
| where (UserPrincipalName has_any (TargetGuests) or TargetGuests has "*")
// Part 2: Enrichment
| extend Country = tostring(LocationDetails.countryOrRegion)
| extend City = tostring(LocationDetails.city)
// Final Output
| project TimeGenerated, UserPrincipalName, UserDisplayName, AppDisplayName, ResultType, IPAddress, Country, City, ConditionalAccessStatus, HomeTenantId
| sort by TimeGenerated desc
| take 50

// NIST 3.10.3 - Guest Invitation and Redemption Tracking
// Part 0: Analyst-Driven Targeting
let TargetOperations = dynamic([]);    // e.g., ["Invite external user", "Redeem external user invite", "Delete external user", "Update invitation"]
let LookbackDays = 90;
// Part 1: Base Filter
AuditLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (array_length(TargetOperations) == 0 or OperationName has_any (TargetOperations))
// Part 2: Enrichment
| extend InitiatedBy_User = tostring(InitiatedBy.user.userPrincipalName)
| extend TargetUser = tostring(TargetResources[0].userPrincipalName)
| extend TargetDisplayName = tostring(TargetResources[0].displayName)
// Final Output
| project TimeGenerated, OperationName, InitiatedBy_User, TargetUser, TargetDisplayName, Result
| sort by TimeGenerated desc
| take 50

// NIST 3.10.3 - Guest/External User Cloud App Activity
// Part 0: Analyst-Driven Targeting
let TargetApps = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
CloudAppEvents
| where TimeGenerated > ago(LookbackDays * 1d)
| where AccountType == "External" or AccountId has "#EXT#"
| where (Application has_any (TargetApps) or TargetApps has "*")
// Final Output
| project TimeGenerated, ActionType, AccountId, Application, ObjectName, ObjectType, IPAddress, CountryCode, City
| sort by TimeGenerated desc
| take 50

// NIST 3.10.3 - Guest User File Access in SharePoint/OneDrive
// Part 0: Analyst-Driven Targeting
let TargetGuests = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
OfficeActivity
| where TimeGenerated > ago(LookbackDays * 1d)
| where UserId has "#ext#" or UserId has "urn:spo:guest"
| where (UserId has_any (TargetGuests) or TargetGuests has "*")
// Part 2: Enrichment
| extend FileExtension = tostring(split(OfficeObjectId, ".")[-1])
// Final Output
| project TimeGenerated, UserId, Operation, OfficeObjectId, FileExtension, Site_Url, ClientIP, OfficeWorkload
| sort by TimeGenerated desc
| take 50

// NIST 3.10.4 - Daily Sign-In Audit Trail Summary
// Part 0: Analyst-Driven Targeting
let TargetUsers = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
SigninLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (UserPrincipalName has_any (TargetUsers) or TargetUsers has "*")
// Part 2: Enrichment
| extend Country = tostring(LocationDetails.countryOrRegion)
| extend City = tostring(LocationDetails.city)
| summarize
    TotalSignIns = count(),
    SuccessCount = countif(ResultType == "0"),
    FailureCount = countif(ResultType != "0"),
    UniqueUsers = dcount(UserPrincipalName),
    UniqueIPs = dcount(IPAddress),
    Countries = make_set(Country, 20)
  by bin(TimeGenerated, 1d)
// Final Output
| project TimeGenerated, TotalSignIns, SuccessCount, FailureCount, UniqueUsers, UniqueIPs, Countries
| sort by TimeGenerated desc
| take 50

// NIST 3.10.4 - Directory Audit Log Completeness Check
// Part 0: Analyst-Driven Targeting
let TargetCategories = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
AuditLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (Category has_any (TargetCategories) or TargetCategories has "*")
// Part 2: Enrichment
| summarize
    EventCount = count(),
    SuccessCount = countif(Result == "success"),
    FailureCount = countif(Result == "failure"),
    UniqueOps = dcount(OperationName)
  by bin(TimeGenerated, 1d), Category
// Final Output
| project TimeGenerated, Category, EventCount, SuccessCount, FailureCount, UniqueOps
| sort by TimeGenerated desc
| take 50

// NIST 3.10.4 - Windows Logon Audit Trail (4624/4625/4634)
// Part 0: Analyst-Driven Targeting
let TargetComputers = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
SecurityEvent
| where TimeGenerated > ago(LookbackDays * 1d)
| where EventID in (4624, 4625, 4634, 4647, 4648)
| where (Computer has_any (TargetComputers) or TargetComputers has "*")
// Part 2: Enrichment
| summarize
    LogonCount = countif(EventID == 4624),
    FailedCount = countif(EventID == 4625),
    LogoffCount = countif(EventID in (4634, 4647)),
    ExplicitCreds = countif(EventID == 4648),
    UniqueAccounts = dcount(TargetAccount)
  by Computer, bin(TimeGenerated, 1d)
// Final Output
| project TimeGenerated, Computer, LogonCount, FailedCount, LogoffCount, ExplicitCreds, UniqueAccounts
| sort by TimeGenerated desc
| take 50

