| project Timestamp, SenderFromAddress, RecipientEmailAddress, Subject, DeliveryAction, DeliveryLocation, DetectionMethods, ThreatTypes, HasPhish, HasMalware
| sort by Timestamp desc
| take 50

// NIST 3.14.2 - Malicious Email Attachment Analysis
// Part 0: Analyst-Driven Targeting
let TargetFileTypes = dynamic([]);    // e.g., [".exe", ".dll", ".ps1", ".vbs", ".js", ".bat", ".cmd", ".scr", ".hta", ".iso", ".img"]
let LookbackDays = 7;
// Part 1: Base Filter
EmailAttachmentInfo
| where Timestamp > ago(LookbackDays * 1d)
// Part 2: Enrichment
| extend FileExtension = tostring(split(FileName, ".")[-1])
| extend IsSuspiciousType = (array_length(TargetFileTypes) == 0 or strcat(".", FileExtension) has_any (TargetFileTypes))
// Final Output
| project Timestamp, NetworkMessageId, SenderFromAddress, RecipientEmailAddress, FileName, FileExtension, FileType, SHA256, IsSuspiciousType, DetectionMethods, ThreatTypes
| sort by Timestamp desc
| take 50

// NIST 3.14.2 - Malicious URL Analysis in Email
// Part 0: Analyst-Driven Targeting
let TargetDomains = dynamic(["*"]);
let LookbackDays = 7;
// Part 1: Base Filter
EmailUrlInfo
| where Timestamp > ago(LookbackDays * 1d)
// Part 2: Enrichment
| extend UrlDomain = tostring(parse_url(Url).Host)
| where (UrlDomain has_any (TargetDomains) or TargetDomains has "*")
// Final Output
| project Timestamp, NetworkMessageId, Url, UrlDomain, UrlLocation
| sort by Timestamp desc
| take 50

// NIST 3.14.2 - Post-Delivery Email Remediation (ZAP)
// Part 0: Analyst-Driven Targeting
let TargetActions = dynamic([]);    // e.g., ["ZAP", "Manual Remediation", "Dynamic Delivery"]
let LookbackDays = 7;
// Part 1: Base Filter
EmailPostDeliveryEvents
| where Timestamp > ago(LookbackDays * 1d)
| where (array_length(TargetActions) == 0 or ActionType has_any (TargetActions))
// Final Output
| project Timestamp, NetworkMessageId, RecipientEmailAddress, ActionType, ActionResult, ActionTrigger, DeliveryLocation
| sort by Timestamp desc
| take 50

// NIST 3.14.2 - Suspicious File Creation Events
// Part 0: Analyst-Driven Targeting
let TargetDevices = dynamic(["*"]);
let SuspiciousExtensions = dynamic([]);    // e.g., [".exe", ".dll", ".ps1", ".vbs", ".js", ".bat", ".cmd", ".scr", ".hta"]
let SuspiciousPaths = dynamic([]);    // e.g., ["\\temp\\", "\\appdata\\local\\temp", "\\downloads\\", "\\public\\"];
let LookbackDays = 7;
// Part 1: Base Filter
DeviceFileEvents
| where Timestamp > ago(LookbackDays * 1d)
| where ActionType == "FileCreated"
| where (DeviceName has_any (TargetDevices) or TargetDevices has "*")
// Part 2: Enrichment
| extend FileExtension = tostring(split(FileName, ".")[-1])
| where (array_length(SuspiciousExtensions) == 0 or strcat(".", FileExtension) has_any (SuspiciousExtensions)) and (array_length(SuspiciousPaths) == 0 or FolderPath has_any (SuspiciousPaths))
// Final Output
| project Timestamp, DeviceName, FileName, FolderPath, FileExtension, SHA256, InitiatingProcessFileName, InitiatingProcessCommandLine, AccountName
| sort by Timestamp desc
| take 50

// NIST 3.14.2 - Active Threat Intelligence IOC Matches
// Part 0: Analyst-Driven Targeting
let TargetThreatTypes = dynamic(["*"]);
let TargetSources = dynamic(["*"]);
// Part 1: Base Filter
ThreatIntelligenceIndicator
| where TimeGenerated > ago(30d)
| where Active == true
| where ExpirationDateTime > now()
| where (ThreatType has_any (TargetThreatTypes) or TargetThreatTypes has "*")
| where (SourceSystem has_any (TargetSources) or TargetSources has "*")
// Final Output
| project TimeGenerated, ThreatType, IndicatorId, NetworkIP, NetworkSourceIP, NetworkDestinationIP, Url, FileHashValue, DomainName, Description, ConfidenceScore, ExpirationDateTime, SourceSystem
| sort by ConfidenceScore desc
| take 50

// NIST 3.5.1 - User Identification via Sign-In Patterns
// Part 0: Analyst-Driven Targeting
let TargetUsers = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
SigninLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (UserPrincipalName has_any (TargetUsers) or TargetUsers has "*")
// Part 2: Enrichment
| summarize
    FirstSeen = min(TimeGenerated),
    LastSeen = max(TimeGenerated),
    SignInCount = count(),
    UniqueApps = dcount(AppDisplayName),
    UniqueIPs = dcount(IPAddress),
    SuccessCount = countif(ResultType == "0"),
    FailureCount = countif(ResultType != "0")
  by UserPrincipalName, UserType
// Final Output
| project UserPrincipalName, UserType, FirstSeen, LastSeen, SignInCount, SuccessCount, FailureCount, UniqueApps, UniqueIPs
| sort by SignInCount desc
| take 50

// NIST 3.5.1 - Full Identity Store Inventory
// Part 0: Analyst-Driven Targeting
let TargetDepartments = dynamic(["*"]);
let TargetCountries = dynamic(["*"]);
// Part 1: Base Filter
IdentityInfo
| where TimeGenerated > ago(14d)
| where (Department has_any (TargetDepartments) or TargetDepartments has "*")
| where (Country has_any (TargetCountries) or TargetCountries has "*")
// Part 2: Enrichment
| summarize arg_max(TimeGenerated, *) by AccountUPN
// Final Output
| project TimeGenerated, AccountUPN, AccountDisplayName, Department, JobTitle, Manager, City, Country, AccountEnabled = IsAccountEnabled, AccountCreationTime, RiskLevel, RiskState, GroupMembership, AssignedRoles
| sort by AccountUPN asc
| take 50

// NIST 3.5.1 - User Provisioning/Deprovisioning Activity
// Part 0: Analyst-Driven Targeting
let TargetSystems = dynamic(["*"]);
let TargetActions = dynamic([]);    // e.g., ["Create", "Update", "Delete", "Disable"]
let LookbackDays = 30;
// Part 1: Base Filter
AADProvisioningLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (array_length(TargetActions) == 0 or Action has_any (TargetActions))
| where (TargetSystem has_any (TargetSystems) or TargetSystems has "*")
// Part 2: Enrichment
| extend SourceId = tostring(SourceIdentity.Name)
| extend TargetId = tostring(TargetIdentity.Name)
// Final Output
| project TimeGenerated, Action, SourceId, TargetId, SourceSystem, TargetSystem, ResultType, StatusInfo
| sort by TimeGenerated desc
| take 50

// NIST 3.5.1 - Windows Account Identification Events
// Part 0: Analyst-Driven Targeting
let TargetComputers = dynamic(["*"]);
let TargetAccounts = dynamic(["*"]);
let EventIDs = dynamic([]);    // e.g., [4720, 4722, 4723, 4724, 4725, 4726, 4738, 4740, 4767]
let LookbackDays = 30;
// Part 1: Base Filter
SecurityEvent
| where TimeGenerated > ago(LookbackDays * 1d)
| where (array_length(EventIDs) == 0 or EventID in (EventIDs))
| where (Computer has_any (TargetComputers) or TargetComputers has "*")
| where (TargetAccount has_any (TargetAccounts) or TargetAccounts has "*")
// Final Output
| project TimeGenerated, Computer, EventID, Activity, TargetAccount, SubjectAccount, IpAddress
| sort by TimeGenerated desc
| take 50

// NIST 3.5.1 - On-Prem Identity Logon Summary
// Part 0: Analyst-Driven Targeting
let TargetAccounts = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
IdentityLogonEvents
| where Timestamp > ago(LookbackDays * 1d)
| where (AccountUpn has_any (TargetAccounts) or TargetAccounts has "*")
// Part 2: Enrichment
| summarize
    LogonCount = count(),
    FailedLogons = countif(ActionType == "LogonFailed"),
    UniqueDevices = dcount(DeviceName),
    Protocols = make_set(Protocol)
  by AccountUpn, AccountDisplayName
// Final Output
| project AccountUpn, AccountDisplayName, LogonCount, FailedLogons, UniqueDevices, Protocols
| sort by LogonCount desc
| take 50

// NIST 3.5.1 - Access Review and Entitlement Changes
// Part 0: Analyst-Driven Targeting
let TargetOperations = dynamic([]);    // e.g., ["Add member to role", "Remove member from role", "Add eligible member to role", "Add user", "Delete user", "Update user"]
let LookbackDays = 30;
// Part 1: Base Filter
AuditLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (array_length(TargetOperations) == 0 or OperationName has_any (TargetOperations))
// Part 2: Enrichment
| extend InitiatedBy_User = tostring(InitiatedBy.user.userPrincipalName)
| extend InitiatedBy_App = tostring(InitiatedBy.app.displayName)
| extend Target = tostring(TargetResources[0].userPrincipalName)
| extend TargetRole = tostring(TargetResources[0].displayName)
// Final Output
| project TimeGenerated, OperationName, InitiatedBy_User, InitiatedBy_App, Target, TargetRole, Result
| sort by TimeGenerated desc
| take 50

// NIST 3.5.1 - ADFS Federated Identity Sign-Ins
// Part 0: Analyst-Driven Targeting
let TargetUsers = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
ADFSSignInLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (UserPrincipalName has_any (TargetUsers) or TargetUsers has "*")
// Part 2: Enrichment
| extend AuthMethod = tostring(AuthenticationDetails)
// Final Output
| project TimeGenerated, UserPrincipalName, AppDisplayName, ResourceDisplayName, ResultType, ResultDescription, IPAddress, TokenIssuerType, AuthMethod
| sort by TimeGenerated desc
| take 50

// NIST 3.5.2 - MFA Enforcement and Authentication Method Analysis
// Part 0: Analyst-Driven Targeting
let TargetUsers = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
SigninLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (UserPrincipalName has_any (TargetUsers) or TargetUsers has "*")
// Part 2: Enrichment
| extend AuthDetail = parse_json(AuthenticationDetails)
| mv-expand AuthDetail
| extend AuthMethod = tostring(AuthDetail.authenticationMethod)
| extend AuthStepResult = tostring(AuthDetail.authenticationStepResultDetail)
| extend AuthStepReq = tostring(AuthDetail.authenticationStepRequirement)
| extend IsMFA = AuthenticationRequirement == "multiFactorAuthentication"
// Final Output
| project TimeGenerated, UserPrincipalName, AppDisplayName, AuthMethod, AuthStepResult, AuthStepReq, IsMFA, AuthenticationRequirement, ConditionalAccessStatus, ResultType
| sort by TimeGenerated desc
| take 50

// NIST 3.5.2 - MFA Registration and Auth Method Changes
// Part 0: Analyst-Driven Targeting
let TargetOperations = dynamic([]);    // e.g., ["User registered security info", "User deleted security info", "User registered all required security info", "Admin registered security info", "User started security info registration"]
let LookbackDays = 30;
// Part 1: Base Filter
AuditLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (array_length(TargetOperations) == 0 or OperationName has_any (TargetOperations))
// Part 2: Enrichment
| extend InitiatedBy_User = tostring(InitiatedBy.user.userPrincipalName)
| extend Target = tostring(TargetResources[0].userPrincipalName)
| extend MethodRegistered = tostring(TargetResources[0].modifiedProperties)
// Final Output
| project TimeGenerated, OperationName, InitiatedBy_User, Target, MethodRegistered, Result
| sort by TimeGenerated desc
| take 50

// NIST 3.5.2 - Non-Interactive Auth Gap (Single Factor Risk)
// Part 0: Analyst-Driven Targeting
let TargetUsers = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
AADNonInteractiveUserSignInLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where AuthenticationRequirement == "singleFactorAuthentication"
| where ResultType == "0"
| where (UserPrincipalName has_any (TargetUsers) or TargetUsers has "*")
// Part 2: Enrichment
| summarize
    SingleFactorCount = count(),
    UniqueApps = dcount(AppDisplayName),
    Apps = make_set(AppDisplayName, 10)
  by UserPrincipalName
// Final Output
| project UserPrincipalName, SingleFactorCount, UniqueApps, Apps
| sort by SingleFactorCount desc
| take 50

// NIST 3.5.2 - CA Policy MFA Gaps (Bypassed or Not Applied)
// Part 0: Analyst-Driven Targeting
let TargetUsers = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
SigninLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where ResultType == "0"
| where AuthenticationRequirement == "singleFactorAuthentication"
| where (UserPrincipalName has_any (TargetUsers) or TargetUsers has "*")
// Part 2: Enrichment
| extend CA_Evaluated = ConditionalAccessPolicies != "[]"
| summarize
    BypassCount = count(),
    UniqueApps = make_set(AppDisplayName, 10),
    UniqueIPs = dcount(IPAddress)
  by UserPrincipalName, CA_Evaluated
// Final Output
| project UserPrincipalName, CA_Evaluated, BypassCount, UniqueApps, UniqueIPs
| sort by BypassCount desc
| take 50

// NIST 3.5.2 - Windows Auth Protocol Monitoring (Kerberos vs NTLM)
// Part 0: Analyst-Driven Targeting
let TargetComputers = dynamic(["*"]);
let TargetAccounts = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
SecurityEvent
| where TimeGenerated > ago(LookbackDays * 1d)
| where EventID == 4624
| where (Computer has_any (TargetComputers) or TargetComputers has "*")
| where (TargetAccount has_any (TargetAccounts) or TargetAccounts has "*")
// Part 2: Enrichment
| extend AuthPackage = AuthenticationPackageName
| extend IsNTLM = AuthPackage has "NTLM"
| summarize
    LogonCount = count(),
    NTLMCount = countif(IsNTLM),
    KerberosCount = countif(AuthPackage has "Kerberos")
  by Computer, TargetAccount
// Final Output
| project Computer, TargetAccount, LogonCount, NTLMCount, KerberosCount, NTLMPercentage = round(100.0 * NTLMCount / LogonCount, 1)
| sort by NTLMPercentage desc
| take 50

// NIST 3.5.2 - On-Prem Auth Protocol Analysis (MDI)
// Part 0: Analyst-Driven Targeting
let TargetAccounts = dynamic(["*"]);
let TargetProtocols = dynamic([]);    // e.g., ["NTLM", "Kerberos", "LDAP", "LDAPClearText"]
let LookbackDays = 30;
// Part 1: Base Filter
IdentityLogonEvents
| where Timestamp > ago(LookbackDays * 1d)
| where (AccountUpn has_any (TargetAccounts) or TargetAccounts has "*")
| where (array_length(TargetProtocols) == 0 or Protocol has_any (TargetProtocols))
// Part 2: Enrichment
| summarize
    LogonCount = count(),
    FailedCount = countif(ActionType == "LogonFailed"),
    UniqueDevices = dcount(DeviceName)
  by AccountUpn, Protocol, LogonType
// Final Output
| project AccountUpn, Protocol, LogonType, LogonCount, FailedCount, UniqueDevices
| sort by LogonCount desc
| take 50

// NIST 3.5.2 - Entra Password Protection Agent Events
// Part 0: Analyst-Driven Targeting
let TargetComputers = dynamic(["*"]);
let LookbackDays = 30;
// Part 1: Base Filter
Event
| where TimeGenerated > ago(LookbackDays * 1d)
| where Source == "Microsoft-AzureADPasswordProtection-DCAgent"
| where (Computer has_any (TargetComputers) or TargetComputers has "*")
// Part 2: Enrichment
| extend PasswordBlocked = EventLevelName == "Warning" or EventLevelName == "Error"
// Final Output
| project TimeGenerated, Computer, EventID, EventLevelName, RenderedDescription, PasswordBlocked
| sort by TimeGenerated desc
| take 50

// NIST 3.5.2 - Self-Service Password Reset Activity
// Part 0: Analyst-Driven Targeting
let TargetOperations = dynamic([]);    // e.g., ["Self-service password reset flow activity progress", "Reset password (self-service)", "Change password (self-service)", "Unlock user account (self-service)"]
let LookbackDays = 30;
// Part 1: Base Filter
AuditLogs
