| where (array_length(TargetOperations) == 0 or OperationName has_any (TargetOperations))
// Part 2: Enrichment
| extend InitiatedBy_User = tostring(InitiatedBy.user.userPrincipalName)
| extend Target = tostring(TargetResources[0].userPrincipalName)
// Final Output
| project TimeGenerated, OperationName, InitiatedBy_User, Target, Result, ResultReason, Category
| sort by TimeGenerated desc
| take 50

// NIST 3.8.3 - Device Wipe and Retire Actions
// Part 0: Analyst-Driven Targeting
let TargetActions = dynamic([]);    // e.g., ["wipe", "retire", "delete", "remoteLock", "resetPasscode"]
let LookbackDays = 90;
// Part 1: Base Filter
IntuneAuditLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (array_length(TargetActions) == 0 or OperationName has_any (TargetActions))
// Part 2: Enrichment
| extend ActorUPN = tostring(Properties.Actor.UPN)
| extend TargetDisplayName = tostring(Properties.TargetDisplayNames)
// Final Output
| project TimeGenerated, OperationName, ActorUPN, TargetDisplayName, ResultType, Properties
| sort by TimeGenerated desc
| take 50

// NIST 3.8.3 - Device Inventory for Disposal Tracking
// Part 0: Analyst-Driven Targeting
let TargetOwnership = dynamic([]);    // e.g., ["Corporate", "Personal"]
let TargetOS = dynamic(["*"]);
// Part 1: Base Filter
IntuneDevices
| where TimeGenerated > ago(1d)
| where (array_length(TargetOwnership) == 0 or OwnerType has_any (TargetOwnership))
| where (OS has_any (TargetOS) or TargetOS has "*")
// Part 2: Enrichment
| summarize arg_max(TimeGenerated, *) by DeviceId
| extend DaysSinceLastSync = datetime_diff('day', now(), LastContact)
| extend StaleDevice = DaysSinceLastSync > 90
// Final Output
| project TimeGenerated, DeviceName, OS, OSVersion, OwnerType, ComplianceState, LastContact, DaysSinceLastSync, StaleDevice, DeviceId, UserName, SerialNumber, StorageTotal, StorageFree
| sort by DaysSinceLastSync desc
| take 50

// NIST 3.8.3 - Device Registration and Deletion in Entra
// Part 0: Analyst-Driven Targeting
let TargetOperations = dynamic([]);    // e.g., ["Delete device", "Add device", "Disable device", "Update device"]
let LookbackDays = 90;
// Part 1: Base Filter
AuditLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (array_length(TargetOperations) == 0 or OperationName has_any (TargetOperations))
// Part 2: Enrichment
| extend InitiatedBy_User = tostring(InitiatedBy.user.userPrincipalName)
| extend DeviceName = tostring(TargetResources[0].displayName)
| extend DeviceId = tostring(TargetResources[0].id)
// Final Output
| project TimeGenerated, OperationName, InitiatedBy_User, DeviceName, DeviceId, Result
