| take 50

// NIST 3.8.3 - BitLocker Recovery Key Access Audit
// Part 0: Analyst-Driven Targeting
let TargetOperations = dynamic([]);    // e.g., ["Read BitLockerKey", "Update device"]
let LookbackDays = 90;
// Part 1: Base Filter
AuditLogs
| where TimeGenerated > ago(LookbackDays * 1d)
| where (array_length(TargetOperations) == 0 or OperationName has_any (TargetOperations))
| where TargetResources has "BitLocker" or OperationName has "BitLocker"
// Part 2: Enrichment
| extend InitiatedBy_User = tostring(InitiatedBy.user.userPrincipalName)
| extend DeviceName = tostring(TargetResources[0].displayName)
// Final Output
| project TimeGenerated, OperationName, InitiatedBy_User, DeviceName, Result
