| take 50

// NIST 3.8.3 - Device Onboarding/Offboarding Status
// Part 0: Analyst-Driven Targeting
let TargetDevices = dynamic(["*"]);
// Part 1: Base Filter
DeviceInfo
| where Timestamp > ago(30d)
| where (DeviceName has_any (TargetDevices) or TargetDevices has "*")
// Part 2: Enrichment
| summarize arg_max(Timestamp, *) by DeviceId
| extend DaysSinceLastSeen = datetime_diff('day', now(), Timestamp)
// Final Output
| project Timestamp, DeviceName, DeviceId, OSPlatform, OSVersion, OnboardingStatus, SensorHealthState, DaysSinceLastSeen, MachineGroup, ExposureLevel, RiskScore
| sort by DaysSinceLastSeen desc
| take 50
